import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { useEffect } from "react";

/**
 * Fetches unread notification links for the current admin user,
 * and returns a Set of admin paths that have pending notifications.
 */
export const useAdminNotificationDots = () => {
  const { user } = useAuth();

  const { data: dotPaths = new Set<string>(), refetch } = useQuery({
    queryKey: ["admin-notification-dots", user?.id],
    queryFn: async () => {
      if (!user) return new Set<string>();

      const { data, error } = await supabase
        .from("notifications")
        .select("link")
        .eq("user_id", user.id)
        .eq("read", false)
        .not("link", "is", null);

      if (error) throw error;

      const paths = new Set<string>();
      for (const row of data || []) {
        if (row.link && row.link.startsWith("/admin")) {
          // Extract the base admin path (e.g. /admin/feedback from /admin/feedback?id=xxx)
          const basePath = row.link.split("?")[0].split("#")[0];
          paths.add(basePath);
        }
      }
      return paths;
    },
    enabled: !!user,
    staleTime: 30_000,
  });

  // Subscribe to realtime changes
  useEffect(() => {
    if (!user) return;

    const channel = supabase
      .channel("admin-notification-dots")
      .on(
        "postgres_changes",
        {
          event: "*",
          schema: "public",
          table: "notifications",
          filter: `user_id=eq.${user.id}`,
        },
        () => refetch()
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user, refetch]);

  return dotPaths;
};
